// Bot Framework Activity schema:
// https://learn.microsoft.com/en-us/azure/bot-service/rest-api/bot-framework-rest-connector-api-reference#activity-object
const body = $input.item.json.body;

const activity = {
  type: body.type ?? 'unknown',
  id: body.id ?? '',
  timestamp: body.timestamp ?? new Date().toISOString(),
  serviceUrl: body.serviceUrl ?? '',
  channelId: body.channelId ?? '',
  conversationId: body.conversation?.id ?? '',
  conversationType: body.conversation?.conversationType ?? '',
  text: (body.text ?? '').trim(),
  fromId: body.from?.id ?? '',
  fromName: body.from?.name ?? '',
  fromAadObjectId: body.from?.aadObjectId ?? '',
  recipientId: body.recipient?.id ?? '',
  recipientName: body.recipient?.name ?? '',
  locale: body.locale ?? 'en-US',
  isGroup: body.conversation?.isGroup ?? false
};

return { json: activity };

// Build a Bot Framework Activity reply
const activity = $input.item.json;

// Echo the user's message with a greeting (replace this logic with your own)
const replyText = `Hello, ${activity.fromName}! You said: "${activity.text}"`;

const replyActivity = {
  type: 'message',
  from: { id: activity.recipientId, name: activity.recipientName },
  recipient: { id: activity.fromId, name: activity.fromName },
  conversation: { id: activity.conversationId },
  replyToId: activity.id,
  text: replyText,
  textFormat: 'plain',
  locale: activity.locale
};

// Build the Bot Connector reply URL:
// POST {serviceUrl}/v3/conversations/{conversationId}/activities
const replyUrl = `${activity.serviceUrl.replace(/\/$/, '')}/v3/conversations/${encodeURIComponent(activity.conversationId)}/activities`;

return {
  json: {
    replyUrl,
    replyActivity,
    conversationId: activity.conversationId,
    serviceUrl: activity.serviceUrl
  }
};

// conversationUpdate fires when members are added/removed.
// Extend this node to send a welcome message on member add.
const activity = $input.item.json;
console.log(`conversationUpdate in channel ${activity.channelId}, conversation ${activity.conversationId}`);
return { json: { handled: true, type: 'conversationUpdate', conversationId: activity.conversationId } };
